// Clean and parse JSON from text fields wrapped in ```
return items.map(item => {
    let text = item.json.text || "";

    // Remove ``` or ```json code block wrappers
    text = text.replace(/^```(json)?\s*/, "").replace(/```$/, "").trim();

    // Parse JSON
    let parsed = {};
    try {
        parsed = JSON.parse(text);
    } catch (err) {
        console.error("JSON parse error:", err);
        parsed = null;
    }

    // Optional: Ensure reference IDs exist in code node
    if (parsed && parsed.action_items) {
        const referenceRegex = /\b[A-Z]{3}-\d{3}-DCN-\d{3}\b/;
        parsed.action_items = parsed.action_items.map(a => {
            const match = a.description.match(referenceRegex) || a.reference?.match(referenceRegex);
            a.code = { reference_id: match ? match[0] : null };
            return a;
        });
    }

    return { json: parsed };
});

const vendors = $input.all();
const vendorsWithMultipleProjects = [];

for (const vendor of vendors) {
  // Count projects based on property_related_projects length
  const projectCount = vendor.json.property_related_projects?.length || 0;

  if (projectCount >= 2) {
    vendorsWithMultipleProjects.push({
      json: {
        vendorId: vendor.json.property_id,
        vendorName: vendor.json.property_name || 'Unknown',
        projectCount
      }
    });
  }
}

return vendorsWithMultipleProjects.length > 0
  ? vendorsWithMultipleProjects
  : [{ json: { skip: true } }];

const actions = $input.all();

const waitingReasons = {};
const blockedReasons = {};

for (const action of actions) {
  const status = action.json.property_status;
  const isOverdue = action.json.property_is_overdue;
  const reason = action.json.property_priority || 'Not specified';
  const project = action.json.property_projects_name || 'Unknown Project';

  // Skip closed tasks
  if (status === 'Closed') continue;

  const key = `${project} | ${reason}`;

  if (isOverdue) {
    blockedReasons[key] = (blockedReasons[key] || 0) + 1;
  } else {
    waitingReasons[key] = (waitingReasons[key] || 0) + 1;
  }
}

const bottlenecks = [];

// Waiting bottlenecks
for (const [key, count] of Object.entries(waitingReasons)) {
  bottlenecks.push({
    type: 'Waiting',
    key,
    count
  });
}

// Blocked bottlenecks
for (const [key, count] of Object.entries(blockedReasons)) {
  bottlenecks.push({
    type: 'Blocked',
    key,
    count
  });
}

// Sort descending by count
return {
  json: {
    bottlenecks: bottlenecks.sort((a, b) => b.count - a.count)
  }
};

const rfiAnalysis = $('Parse RFI Analysis').first().json;
const bottlenecks = $('Identify Bottlenecks').first().json;

const reportDate = new Date().toISOString().split('T')[0];

function generateThemeSection(themes) {
  if (!themes || themes.length === 0) {
    return '<p><em>No significant patterns detected</em></p>';
  }

  return themes.slice(0, 5).map(theme => `
    <div style="background: white; padding: 15px; margin: 12px 0; border-left: 4px solid #2563eb;">
      <h4 style="margin: 0 0 8px 0; color: #2563eb;">${theme.theme}</h4>
      <p style="margin: 4px 0;"><strong>Frequency:</strong> ${theme.count} RFIs</p>
      <p style="margin: 4px 0;"><strong>Suggested Action:</strong> ${theme.suggested_action}</p>
    </div>
  `).join('');
}

function generateBottleneckSection(bottlenecks) {
  if (!bottlenecks.bottlenecks || bottlenecks.bottlenecks.length === 0) {
    return '<p><em>No significant bottlenecks detected</em></p>';
  }

  return bottlenecks.bottlenecks.map(bn => `
    <div style="background: white; padding: 15px; margin: 12px 0; border-left: 4px solid #f59e0b;">
      <h4 style="margin: 0 0 8px 0; color: #f59e0b;">${bn.type}: ${bn.key}</h4>
      <p style="margin: 4px 0;"><strong>Affected Actions:</strong> ${bn.count}</p>
    </div>
  `).join('');
}

