const rfis = $('Get many database pages').all() || [];

if (rfis.length === 0) {
  return [{json: {skip: true, subjects: []}}];
}

const subjects = rfis.map(rfi => {
  const reference = rfi.json.property_reference;
  const subject = rfi.json.property_subject;
  return `${reference}: ${subject}`;
});

return [{
  json: {
    skip: false,
    subjects: subjects,
    totalRFIs: rfis.length
  }
}];
